using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.EDocuments.Domain.Entities;namespace verii_metivon_api.Modules.EDocuments.Infrastructure.Persistence.Configurations;
public sealed class CompanyLegalProfileConfiguration:IEntityTypeConfiguration<CompanyLegalProfile>{public void Configure(EntityTypeBuilder<CompanyLegalProfile>b){b.ToTable("RII_COMPANY_LEGAL_PROFILES");b.HasIndex(x=>x.BranchId).IsUnique();b.Property(x=>x.TaxNumber).HasMaxLength(11).IsRequired();b.Property(x=>x.LegalName).HasMaxLength(250).IsRequired();}}
public sealed class EDocumentProviderConfigurationMap:IEntityTypeConfiguration<EDocumentProviderConfiguration>{public void Configure(EntityTypeBuilder<EDocumentProviderConfiguration>b){b.ToTable("RII_EDOCUMENT_PROVIDER_CONFIGURATIONS");b.HasIndex(x=>new{x.BranchId,x.ProviderType,x.Environment}).IsUnique();b.Property(x=>x.CredentialReference).HasMaxLength(200).IsRequired();}}
public sealed class ElectronicDocumentConfiguration:IEntityTypeConfiguration<ElectronicDocument>{public void Configure(EntityTypeBuilder<ElectronicDocument>b){b.ToTable("RII_ELECTRONIC_DOCUMENTS");b.HasIndex(x=>x.Uuid).IsUnique();b.HasIndex(x=>new{x.DocumentType,x.DocumentNumber}).IsUnique();b.HasIndex(x=>new{x.SourceType,x.SourceId,x.DocumentType});b.Property(x=>x.DocumentNumber).HasMaxLength(40).IsRequired();b.Property(x=>x.PayloadXml).HasColumnType("nvarchar(max)");}}
public sealed class ElectronicDocumentStatusHistoryConfiguration:IEntityTypeConfiguration<ElectronicDocumentStatusHistory>{public void Configure(EntityTypeBuilder<ElectronicDocumentStatusHistory>b){b.ToTable("RII_ELECTRONIC_DOCUMENT_STATUS_HISTORY");b.HasIndex(x=>new{x.ElectronicDocumentId,x.OccurredAt});b.HasOne(x=>x.ElectronicDocument).WithMany(x=>x.History).HasForeignKey(x=>x.ElectronicDocumentId).OnDelete(DeleteBehavior.Restrict);b.Property(x=>x.RawResponse).HasColumnType("nvarchar(max)");}}
public sealed class EDocumentParameterSettingsConfiguration:IEntityTypeConfiguration<EDocumentParameterSettings>{public void Configure(EntityTypeBuilder<EDocumentParameterSettings>b){b.ToTable("RII_EDOCUMENT_PARAMETERS",t=>{t.HasCheckConstraint("CK_RII_EDOCUMENT_PARAMETERS_TIMINGS","[RetryDelayMinutes] >= 1 AND [RetryDelayMinutes] <= 1440 AND [StatusPollingIntervalMinutes] >= 1 AND [StatusPollingIntervalMinutes] <= 1440");t.HasCheckConstraint("CK_RII_EDOCUMENT_PARAMETERS_RETENTION","[ArchiveRetentionYears] >= 1 AND [ArchiveRetentionYears] <= 20 AND [MaximumXmlSizeKb] >= 64 AND [MaximumXmlSizeKb] <= 10240");});b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>x.BranchId).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.ProviderEnvironment).HasMaxLength(20).IsRequired();b.Property(x=>x.DefaultInvoiceScenario).HasMaxLength(30).IsRequired();b.Property(x=>x.DefaultArchiveInvoiceScenario).HasMaxLength(30).IsRequired();b.Property(x=>x.DefaultDespatchScenario).HasMaxLength(30).IsRequired();b.Property(x=>x.DefaultCurrencyCode).HasMaxLength(3).IsUnicode(false).IsRequired();b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.DefaultCurrency).WithMany().HasForeignKey(x=>x.DefaultCurrencyId).OnDelete(DeleteBehavior.Restrict);}}
